import{_ as t,o as e,c as r,a0 as l}from"./chunks/framework.D7jNN1Sc.js";const m=JSON.parse('{"title":"MA Material Helper","description":"","frontmatter":{},"headers":[],"relativePath":"features/ma-material-helper.md","filePath":"features/ma-material-helper.md"}'),d={name:"features/ma-material-helper.md"};function i(o,a,s,p,n,h){return e(),r("div",null,[...a[0]||(a[0]=[l(`<h1 id="ma-material-helper" tabindex="-1">MA Material Helper <a class="header-anchor" href="#ma-material-helper" aria-label="Permalink to &quot;MA Material Helper&quot;">​</a></h1><p>Modular Avatar のマテリアル制御コンポーネントを使った色変更メニューを自動生成します。カラーバリエーションの Prefab から数クリックで色変更メニューを作成でき、複数 Prefab からの同時生成にも対応しています。</p><p><strong>必要条件:</strong> <a href="https://modular-avatar.nadena.dev/ja" target="_blank" rel="noreferrer">Modular Avatar</a> 1.13.0 以上</p><h2 id="使い方" tabindex="-1">使い方 <a class="header-anchor" href="#使い方" aria-label="Permalink to &quot;使い方&quot;">​</a></h2><ol><li>カラーバリエーション Prefab を選択 → 右クリック → <code>Copy Material Setup</code>（複数選択可）</li><li>ターゲットの衣装を選択 → 右クリック → 以下のいずれかを選択:</li></ol><table tabindex="0"><thead><tr><th>コマンド</th><th>説明</th></tr></thead><tbody><tr><td><code>Create Material Setter</code></td><td>各スロットに直接マテリアルを設定（<strong>推奨</strong>）</td></tr><tr><td><code>[Optional] Create Material Setter (All Slots)</code></td><td>すべてのスロットに Setter を作成（カスタマイズ用）</td></tr><tr><td><code>Create Material Swap</code></td><td>マテリアルの置き換えルールで設定</td></tr><tr><td><code>[Optional] Create Material Swap (Per Object)</code></td><td>オブジェクトごとに個別の Swap を作成</td></tr></tbody></table><p>番号付きカラーバリエーション（Color1、Color2 など）を含む「Color Menu」が自動作成されます。</p><h2 id="material-setter-と-material-swap-の違い" tabindex="-1">Material Setter と Material Swap の違い <a class="header-anchor" href="#material-setter-と-material-swap-の違い" aria-label="Permalink to &quot;Material Setter と Material Swap の違い&quot;">​</a></h2><p>基本的には <strong>Material Setter を推奨</strong>します。</p><table tabindex="0"><thead><tr><th></th><th>Material Setter</th><th>Material Swap</th></tr></thead><tbody><tr><td>設定単位</td><td>スロット単位</td><td>マテリアル名単位</td></tr><tr><td>同一メッシュで同じマテリアルを別々の変更先に</td><td>対応</td><td>非対応</td></tr><tr><td>用途</td><td>ほとんどのケース</td><td>シンプルな構成</td></tr></tbody></table><h3 id="material-swap-が対応できないケース" tabindex="-1">Material Swap が対応できないケース <a class="header-anchor" href="#material-swap-が対応できないケース" aria-label="Permalink to &quot;Material Swap が対応できないケース&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>メッシュA:</span></span>
<span class="line"><span>  スロット0: マテリアルX → マテリアルY に変更したい</span></span>
<span class="line"><span>  スロット1: マテリアルX → マテリアルZ に変更したい</span></span></code></pre></div><p>Material Swap は「マテリアルX」を1つのマテリアルにしか置き換えられないため、両スロットが同じ結果になります。Material Setter ならスロット単位で異なるマテリアルを指定できます。</p><h2 id="アクセス方法" tabindex="-1">アクセス方法 <a class="header-anchor" href="#アクセス方法" aria-label="Permalink to &quot;アクセス方法&quot;">​</a></h2><p>ヒエラルキー右クリック → <code>Kanameliser Editor Plus &gt; Copy Material Setup / Create Material Setter / Create Material Swap</code></p>`,15)])])}const b=t(d,[["render",i]]);export{m as __pageData,b as default};
